package com.ruoyi.modules.invest.benefit.evaluation.service.impl;
import com.ruoyi.common.utils.DateUtils;import com.ruoyi.common.utils.ShiroUtils;import com.ruoyi.modules.invest.benefit.evaluation.domain.InvestBenefitEvaluation;import com.ruoyi.modules.invest.benefit.evaluation.mapper.InvestBenefitEvaluationMapper;import com.ruoyi.modules.invest.benefit.evaluation.service.IInvestBenefitEvaluationService;import com.ruoyi.modules.invest.project.domain.InvestProject;import com.ruoyi.modules.invest.project.mapper.InvestProjectMapper;import org.springframework.beans.factory.annotation.Autowired;import org.springframework.stereotype.Service;import java.math.*;import java.util.List;@Service public class InvestBenefitEvaluationServiceImpl implements IInvestBenefitEvaluationService{@Autowired private InvestBenefitEvaluationMapper mapper;@Autowired private InvestProjectMapper projectMapper;public InvestBenefitEvaluation selectById(Long id){return mapper.selectById(id);}public List<InvestBenefitEvaluation> selectList(InvestBenefitEvaluation e){return mapper.selectList(e);}public int insert(InvestBenefitEvaluation e){fill(e);e.setCreateBy(ShiroUtils.getLoginName());e.setCreateTime(DateUtils.getNowDate());e.setDelFlag("0");if(e.getEvaluationStatus()==null)e.setEvaluationStatus("0");calc(e);if(e.getEvaluationCode()==null||e.getEvaluationCode().isEmpty())e.setEvaluationCode("EVA-"+System.currentTimeMillis());return mapper.insert(e);}public int update(InvestBenefitEvaluation e){fill(e);calc(e);e.setUpdateBy(ShiroUtils.getLoginName());e.setUpdateTime(DateUtils.getNowDate());return mapper.update(e);}public int deleteByIds(Long[] ids){return mapper.deleteByIds(ids);}public boolean calculate(Long id){InvestBenefitEvaluation e=mapper.selectById(id);if(e==null)return false;calc(e);return mapper.update(e)>0;}private void calc(InvestBenefitEvaluation e){BigDecimal income=e.getActualIncome()==null?BigDecimal.ZERO:e.getActualIncome();BigDecimal profit=e.getActualProfit()==null?BigDecimal.ZERO:e.getActualProfit();e.setActualRoi(income.compareTo(BigDecimal.ZERO)==0?BigDecimal.ZERO:profit.multiply(new BigDecimal("100")).divide(income,2,RoundingMode.HALF_UP));e.setActualScore(e.getActualRoi());}private void fill(InvestBenefitEvaluation e){if(e.getProjectId()==null)return;InvestProject p=projectMapper.selectInvestProjectById(e.getProjectId());if(p!=null){e.setProjectName(p.getProjectName());e.setSchemeId(p.getSchemeId());}}}